  1	import * as React from 'react';
  2	import cx from 'classnames';
  3	import * as _ from 'lodash';
  4	import { useTranslation } from 'react-i18next';
  5	import { Link } from 'react-router-dom-v5-compat';
  6	import { Tooltip } from '@patternfly/react-core';
  7	import QuestionCircleIcon from '@patternfly/react-icons/dist/js/icons/question-circle-icon';
  8	import { t_color_gray_40 as customTaskColor } from '@patternfly/react-tokens/dist/js/t_color_gray_40';
  9	import {
 10	  observer,
 11	  Node,
 12	  NodeModel,
 13	  useHover,
 14	  createSvgIdUrl,
 15	} from '@patternfly/react-topology';
 16	import {
 17	  K8sResourceKind,
 18	  WatchK8sResults,
 19	  getGroupVersionKindForModel,
 20	  useK8sWatchResources,
 21	} from '@openshift-console/dynamic-plugin-sdk';
 22	import { CustomRunKind, TaskKind } from '../../types';
 23	import { truncateMiddle } from './truncate-middle';
 24	import SvgDropShadowFilter from './SvgDropShadowFilter';
 25	import { CustomRunModelV1Beta1 } from '../../models';
 26	import { TaskNodeModelData } from './types';
 27	import { resourcePathFromModel } from '../utils/utils';
 28	
 29	import './CustomTaskNode.scss';
 30	
 31	type CustomTaskNodeProps = {
 32	  element: Node<NodeModel, TaskNodeModelData>;
 33	  disableTooltip?: boolean;
 34	};
 35	
 36	type WatchResource = {
 37	  [key: string]: K8sResourceKind[] | K8sResourceKind;
 38	};
 39	
 40	interface CustomTaskProps {
 41	  pipelineRunName?: string;
 42	  name: string;
 43	  loaded?: boolean;
 44	  task?: {
 45	    data: TaskKind;
 46	  };
 47	  namespace: string;
 48	  disableVisualizationTooltip?: boolean;
 49	  width: number;
 50	  height: number;
 51	  customTask?: K8sResourceKind;
 52	}
 53	
 54	const FILTER_ID = 'SvgTaskDropShadowFilterId';
 55	
 56	const CustomTaskComponent: React.FC<CustomTaskProps> = ({
 57	  pipelineRunName,
 58	  namespace,
 59	  task,
 60	  name,
 61	  disableVisualizationTooltip,
 62	  width,
 63	  height,
 64	  customTask,
 65	}) => {
 66	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 67	  const showStatusState = !!pipelineRunName;
 68	  const visualName = name || _.get(task, ['metadata', 'name'], '');
 69	  const nameRef = React.useRef();
 70	  const pillRef = React.useRef();
 71	
 72	  const path = `${resourcePathFromModel(
 73	    CustomRunModelV1Beta1,
 74	    customTask?.metadata?.name,
 75	    namespace,
 76	  )}`;
 77	  const enableLogLink = !!path;
 78	  const [hover, hoverRef] = useHover();
 79	  const truncatedVisualName = React.useMemo(
 80	    () =>
 81	      truncateMiddle(visualName, {
 82	        length: showStatusState ? 11 : 14,
 83	        truncateEnd: true,
 84	      }),
 85	    [visualName, showStatusState],
 86	  );
 87	
 88	  const renderVisualName = (
 89	    <text
 90	      ref={nameRef}
 91	      x={showStatusState ? 30 : width / 2}
 92	      y={height / 2 + 1}
 93	      className={cx('odc-pipeline-vis-task-text', {
 94	        'is-text-center': !pipelineRunName,
 95	        'is-linked': enableLogLink,
 96	      })}
 97	    >
 98	      {truncatedVisualName}
 99	    </text>
100	  );
101	
102	  let taskPill = (
103	    <g ref={hoverRef}>
104	      <SvgDropShadowFilter dy={1} id={FILTER_ID} />
105	      <rect
106	        filter={hover ? createSvgIdUrl(FILTER_ID) : ''}
107	        width={width}
108	        height={height}
109	        rx={5}
110	        className={cx('odc-pipeline-vis-task', {
111	          'is-selected': !!pipelineRunName && hover,
112	          'is-linked': !!pipelineRunName && enableLogLink,
113	        })}
114	        style={{
115	          stroke: customTaskColor.value,
116	        }}
117	      />
118	      {visualName !== truncatedVisualName && disableVisualizationTooltip ? (
119	        <Tooltip triggerRef={nameRef} content={visualName}>
120	          {renderVisualName}
121	        </Tooltip>
122	      ) : (
123	        renderVisualName
124	      )}
125	
126	      {showStatusState && (
127	        <>
128	          <svg
129	            width={30}
130	            height={30}
131	            viewBox="-10 -7 30 30"
132	            style={{
133	              color: customTaskColor.value,
134	            }}
135	          >
136	            {<QuestionCircleIcon />}
137	          </svg>
138	        </>
139	      )}
140	    </g>
141	  );
142	
143	  if (!disableVisualizationTooltip) {
144	    taskPill = (
145	      <Tooltip
146	        triggerRef={pillRef}
147	        position="bottom"
148	        enableFlip={false}
149	        content={t('Custom Task')}
150	      >
151	        <g ref={pillRef}>{taskPill}</g>
152	      </Tooltip>
153	    );
154	  }
155	  return (
156	    <g
157	      className={cx('odc-pipeline-topology__task-node', {
158	        'is-link': enableLogLink,
159	      })}
160	    >
161	      {enableLogLink ? <Link to={path}>{taskPill}</Link> : taskPill}
162	    </g>
163	  );
164	};
165	
166	const CustomTaskNode: React.FC<CustomTaskNodeProps> = ({
167	  element,
168	  disableTooltip,
169	}) => {
170	  const { height, width } = element.getBounds();
171	
172	  const { pipeline, pipelineRun, task } = element.getData();
173	
174	  const customTaskName = `${pipelineRun?.metadata?.name}-${task?.name}`;
175	
176	  const watchedResources = {
177	    customRun: {
178	      groupVersionKind: getGroupVersionKindForModel(CustomRunModelV1Beta1),
179	      name: customTaskName,
180	      namespace: pipeline?.metadata?.namespace,
181	      prop: 'task',
182	    },
183	  };
184	
185	  const resourcesData: WatchK8sResults<WatchResource> =
186	    useK8sWatchResources<WatchResource>(watchedResources);
187	
188	  const taskComponent: JSX.Element = (
189	    <CustomTaskComponent
190	      pipelineRunName={pipelineRun?.metadata?.name}
191	      name={task.name || ''}
192	      task={task.taskSpec && { data: { spec: task.taskSpec } }}
193	      namespace={pipeline?.metadata?.namespace}
194	      disableVisualizationTooltip={disableTooltip}
195	      width={width}
196	      height={height}
197	      customTask={resourcesData.customRun?.data as CustomRunKind}
198	    />
199	  );
200	  return taskComponent;
201	};
202	
203	export default React.memo(observer(CustomTaskNode));

